    val N = n.toInt()
    val dsu = DSU(N)
    var addedEdgesCount = 0L

    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val w = edge[2].toInt()

        // The union method returns true if the edge should be added
        if (dsu.union(u, v, w)) {
            addedEdgesCount++
        }
    }

    return addedEdgesCount
}
